INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("急に牛乳と卵が欲しいっつうから\n何かと思ったけんど、まさか\nオラのためにこんな立派なケーキ\n用意してくれてただなんてな！", 0, 0, 6, 103311, 1033501, 1, 11, "", 1033501040, 1);
