INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("みんなで過ごすのがオラにとって\n最高の誕生日だべ！\nあんがとな、あんちゃん！", 0, 0, 6, 103311, 1033501, 1, 11, "", 1033501052, 1);
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 0, 1033501, "", 91, "", 1033501053, "");
