INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("わあ……素敵なケーキね！\nえ？　キミが作ったの？\nすごいじゃない！", 0, 0, 4, 103411, 1034501, 1, 11, "", 1034501040, 1);
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 0, 1034501, "", 91, "", 1034501041, "");
