INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("なんでって、それは……\nキミがお祝いに来てくれるかも、\nなんて思ってたから……", 0, 0, 5, 103411, 1034501, 1, 11, "", 1034501046, 1);
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 0, 1034501, "", 91, "", 1034501047, "");
