INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("にゃはは～！\n誕生日のお祝いしてくれて\nどうもありがとにゃ！", 0, 0, 6, 104611, 1046501, 1, 11, "", 1046501040, 1);
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 0, 1046501, "", 91, "", 1046501041, "");
