INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("にゃっふっふ……\nそれじゃ今度、絶品のたい焼きを\nキミにごちそうしてあげるにゃ！\n楽しみに待ってるといいにゃ♪", 0, 0, 6, 104611, 1046501, 1, 11, "", 1046501049, 1);
