INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("お祝いしてくれてありがとう！\n私の誕生日、覚えててくれたんだね。\nすごくうれしいな。", 0, 0, 6, 105711, 1057501, 1, 11, "", 1057501040, 1);
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 0, 1057501, "", 91, "", 1057501041, "");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("vo_adv_1057501_001", "", "", 0, "vo_adv_1057501", 1057501, 0, 21, "", 1057501042, "");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("このケーキ、すごく美味しそうだね。\n有名なお店のケーキなのかな？\nえ？　あなたが自分で作ってくれたの？\nすごーい！", 0, 0, 5, 105711, 1057501, 1, 11, "", 1057501043, 1);
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 0, 1057501, "", 91, "", 1057501044, "");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("vo_adv_1057501_002", "", "", 0, "vo_adv_1057501", 1057501, 0, 21, "", 1057501045, "");
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("なんだかやる気が出てきちゃった！\nもしよかったら、このあと一緒に\n依頼を受けにいこうよ！", 0, 0, 7, 105711, 1057501, 1, 11, "", 1057501046, 1);
INSERT INTO `v1_090bb34aa14323c05c0750f1ed6cf60d4e0c724484619bf4847c022e8619dc54` VALUES ("", "", "", "", 0, 1057501, "", 91, "", 1057501047, "");
